SELECT cat_no, m_r_p
FROM relays
WHERE relay_id = 1;

SELECT cat_no, m_r_p
FROM relays
WHERE type_of_mounting = 'None';

SELECT AVG(l.session_duration) AS average_edit_session_duration
FROM access_logs l
WHERE l.access_type = 'edit' AND l.access_date BETWEEN '2023-10-01' AND '2023-10-31';

SELECT type_of_mounting, MAX(m_r_p) AS max_mrp
FROM relays
GROUP BY type_of_mounting;
